member.example:
Bind the RectTransform anchored position using a serialized binder field — the target RectTransform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RectTransformAnchoredPositionBinder _anchoredPosition;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _anchoredPosition;
    }


Bind the RectTransform anchored position by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private RectTransform _target;
        
        private RectTransformAnchoredPositionBinder AnchoredPosition =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _anchoredPosition;
    }

Switch the RectTransform anchored position between two values using a serialized binder field — the target RectTransform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RectTransformAnchoredPositionSwitcherBinder _isVisible;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }


Switch the RectTransform anchored position between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RectTransform _target;
        
        [SerializeField]
        private Vector3 _visiblePosition;
        
        [SerializeField]
        private Vector3 _hiddenPosition;
        
        private RectTransformAnchoredPositionSwitcherBinder IsVisible => new(
            _target, _visiblePosition, _hiddenPosition);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }
